{
  "name": "TexRead - Trình Đọc File LaTeX Thông Minh",
  "description": "Một ứng dụng hiện đại cho phép bạn tải lên nhiều tệp .tex và chuyển đổi nội dung LaTeX phức tạp thành văn bản thuần túy hoặc Markdown dễ đọc bằng sức mạnh của AI Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TexFile {
  id: string;
  name: string;
  rawContent: string;
  processedContent?: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  error?: string;
}

export interface GeminiResponse {
  text: string;
}

import { GoogleGenAI } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const processTexContent = async (texContent: string): Promise<string> => {
  const ai = getAIClient();

  const prompt = `
    Dưới đây là nội dung của một file LaTeX (.tex). 
    Nhiệm vụ của bạn là chuyển đổi nội dung này sang dạng văn bản thuần túy (Plain Text) hoặc Markdown dễ đọc nhất cho con người.

    Yêu cầu:
    1. Loại bỏ các mã boilerplate LaTeX không cần thiết (như \\documentclass, \\usepackage, \\begin{document}, v.v.).
    2. Giữ lại cấu trúc nội dung chính (tiêu đề, các phần, danh sách).
    3. Nếu có bảng biểu hoặc công thức toán học, hãy trình bày lại sao cho dễ hiểu nhất ở dạng văn bản.
    4. Trả về kết quả bằng tiếng Việt nếu nội dung gốc là tiếng Việt, hoặc giữ nguyên ngôn ngữ gốc nếu là ngôn ngữ khác.
    5. Chỉ trả về nội dung đã chuyển đổi, không thêm lời dẫn giải của AI.

    Nội dung LaTeX:
    ---
    ${texContent}
    ---
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.2,
        topP: 0.8,
        topK: 40,
      }
    });

    return response.text || "Không thể xử lý nội dung này.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Lỗi khi kết nối với AI. Vui lòng thử lại sau.");
  }
};

import React from 'react';
import { TexFile } from '../types';

interface FileCardProps {
  file: TexFile;
  onRemove: (id: string) => void;
}

const FileCard: React.FC<FileCardProps> = ({ file, onRemove }) => {
  return (
    <div className="bg-white rounded-xl shadow-md overflow-hidden border border-blue-100 transition-all hover:shadow-lg mb-6">
      <div className="p-4 bg-gradient-to-r from-blue-600 to-indigo-600 flex justify-between items-center text-white">
        <div className="flex items-center space-x-3">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
          <h3 className="font-semibold truncate max-w-[200px] md:max-w-md">{file.name}</h3>
        </div>
        <div className="flex items-center space-x-4">
          <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${
            file.status === 'completed' ? 'bg-green-400 text-green-900' :
            file.status === 'processing' ? 'bg-yellow-400 text-yellow-900 animate-pulse' :
            file.status === 'error' ? 'bg-red-400 text-red-900' : 'bg-gray-400 text-gray-900'
          }`}>
            {file.status === 'completed' ? 'Hoàn tất' : 
             file.status === 'processing' ? 'Đang xử lý...' : 
             file.status === 'error' ? 'Lỗi' : 'Chờ'}
          </span>
          <button 
            onClick={() => onRemove(file.id)}
            className="hover:bg-white/20 p-1 rounded-full transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      </div>

      <div className="p-5 max-h-[500px] overflow-y-auto bg-slate-50">
        {file.status === 'processing' && (
          <div className="flex flex-col items-center justify-center py-12 text-blue-600">
            <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-sm font-medium">AI đang đọc và chuyển đổi nội dung LaTeX...</p>
          </div>
        )}

        {file.status === 'error' && (
          <div className="p-4 bg-red-50 text-red-700 border border-red-200 rounded-lg">
            <p className="font-bold mb-1">Đã xảy ra lỗi:</p>
            <p>{file.error}</p>
          </div>
        )}

        {file.status === 'completed' && file.processedContent && (
          <div className="prose prose-blue max-w-none">
            <pre className="whitespace-pre-wrap font-sans text-gray-800 leading-relaxed text-sm md:text-base">
              {file.processedContent}
            </pre>
          </div>
        )}

        {file.status === 'pending' && (
          <div className="text-center py-8 text-gray-400 italic text-sm">
            Đang chờ để bắt đầu xử lý...
          </div>
        )}
      </div>
    </div>
  );
};

export default FileCard;

import React, { useState, useCallback, useRef } from 'react';
import { TexFile } from './types';
import { processTexContent } from './services/geminiService';
import FileCard from './components/FileCard';

const App: React.FC = () => {
  const [files, setFiles] = useState<TexFile[]>([]);
  const [isProcessingAll, setIsProcessingAll] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = event.target.files;
    if (!selectedFiles) return;

    const newTexFiles: TexFile[] = [];

    for (let i = 0; i < selectedFiles.length; i++) {
      const file = selectedFiles[i];
      if (file.name.endsWith('.tex') || file.type === 'application/x-tex') {
        const text = await file.text();
        newTexFiles.push({
          id: Math.random().toString(36).substring(7),
          name: file.name,
          rawContent: text,
          status: 'pending'
        });
      }
    }

    setFiles(prev => [...prev, ...newTexFiles]);

    // Reset input so the same file can be picked again if removed
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const processFile = useCallback(async (file: TexFile) => {
    setFiles(prev => prev.map(f => f.id === file.id ? { ...f, status: 'processing' } : f));

    try {
      const result = await processTexContent(file.rawContent);
      setFiles(prev => prev.map(f => f.id === file.id ? { 
        ...f, 
        status: 'completed', 
        processedContent: result 
      } : f));
    } catch (error: any) {
      setFiles(prev => prev.map(f => f.id === file.id ? { 
        ...f, 
        status: 'error', 
        error: error.message || "Lỗi không xác định" 
      } : f));
    }
  }, []);

  const handleProcessAll = async () => {
    const pendingFiles = files.filter(f => f.status === 'pending' || f.status === 'error');
    if (pendingFiles.length === 0) return;

    setIsProcessingAll(true);
    for (const file of pendingFiles) {
      await processFile(file);
    }
    setIsProcessingAll(false);
  };

  const removeFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const clearAll = () => {
    setFiles([]);
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-10 md:py-16">
      {/* Header Section */}
      <header className="text-center mb-12">
        <div className="inline-block p-3 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-700 shadow-xl mb-6">
          <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
          </svg>
        </div>
        <h1 className="text-4xl font-extrabold text-blue-900 mb-3 tracking-tight">TexRead</h1>
        <p className="text-lg text-blue-600 max-w-2xl mx-auto font-medium">
          Chuyển đổi file LaTeX sang văn bản dễ đọc ngay lập tức với AI. Không cần cài đặt phần mềm LaTeX phức tạp.
        </p>
      </header>

      {/* Main Action Area */}
      <div className="sticky top-6 z-30 mb-10">
        <div className="bg-white/80 backdrop-blur-md p-6 rounded-2xl shadow-xl border border-blue-100 flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex-1 w-full">
            <label className="relative flex flex-col items-center justify-center w-full h-32 border-2 border-blue-300 border-dashed rounded-xl cursor-pointer bg-blue-50 hover:bg-blue-100 transition-colors group">
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                <svg className="w-8 h-8 mb-3 text-blue-500 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                </svg>
                <p className="mb-2 text-sm text-blue-700 font-semibold uppercase tracking-wider">
                  Tải lên file .tex
                </p>
                <p className="text-xs text-blue-500">Hỗ trợ chọn nhiều file cùng lúc</p>
              </div>
              <input 
                ref={fileInputRef}
                type="file" 
                className="hidden" 
                multiple 
                accept=".tex" 
                onChange={handleFileChange}
              />
            </label>
          </div>

          <div className="flex flex-col gap-2 w-full md:w-auto">
            <button
              onClick={handleProcessAll}
              disabled={isProcessingAll || files.filter(f => f.status === 'pending' || f.status === 'error').length === 0}
              className={`px-8 py-3 rounded-xl font-bold text-white transition-all transform active:scale-95 flex items-center justify-center gap-2 ${
                isProcessingAll || files.filter(f => f.status === 'pending' || f.status === 'error').length === 0
                  ? 'bg-gray-400 cursor-not-allowed'
                  : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:shadow-lg hover:shadow-blue-200'
              }`}
            >
              {isProcessingAll ? (
                <>
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                  Đang xử lý...
                </>
              ) : (
                <>
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                  Bắt đầu đọc
                </>
              )}
            </button>

            {files.length > 0 && (
              <button
                onClick={clearAll}
                className="px-8 py-3 rounded-xl font-bold text-blue-600 hover:bg-blue-50 transition-colors border border-blue-200"
              >
                Xóa tất cả
              </button>
            )}
          </div>
        </div>
      </div>

      {/* File List */}
      <div className="space-y-6">
        {files.length === 0 ? (
          <div className="text-center py-20 bg-white/50 rounded-3xl border-2 border-dashed border-blue-200">
            <div className="bg-blue-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
              </svg>
            </div>
            <p className="text-blue-900 font-bold text-xl mb-1">Chưa có tệp nào</p>
            <p className="text-blue-500">Hãy tải lên một vài file .tex để bắt đầu trải nghiệm</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-6">
            {files.map(file => (
              <FileCard 
                key={file.id} 
                file={file} 
                onRemove={removeFile} 
              />
            ))}
          </div>
        )}
      </div>

      {/* Footer */}
      <footer className="mt-20 pt-8 border-t border-blue-200 text-center text-blue-400 text-sm">
        <p>&copy; {new Date().getFullYear()} TexRead - Được hỗ trợ bởi Gemini AI</p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

export type ProcessingAction = 'CLEAN_ID' | 'REMOVE_SOLUTION' | 'SORT_FORMAT' | 'GENERAL_FORMAT';

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const processTexContent = async (texContent: string, action: ProcessingAction = 'GENERAL_FORMAT'): Promise<string> => {
  const ai = getAIClient();

  let actionInstruction = "";
  switch(action) {
    case 'CLEAN_ID':
      actionInstruction = "Xóa toàn bộ các mã ID, mã nhận diện câu hỏi (ví dụ các chuỗi số trong ngoặc vuông [] hoặc các định dạng ID riêng biệt). Giữ nguyên nội dung câu hỏi.";
      break;
    case 'REMOVE_SOLUTION':
      actionInstruction = "Xóa toàn bộ phần lời giải (environments như \\begin{solution}...\\end{solution} hoặc các phần ghi chú giải đề). Chỉ giữ lại đề bài.";
      break;
    case 'SORT_FORMAT':
      actionInstruction = "Sắp xếp lại các câu hỏi theo thứ tự logic, chuẩn hóa định dạng LaTeX để dễ đọc nhất (xuống dòng chuẩn '\\\\' trong lời giải, làm sạch mã thừa).";
      break;
    default:
      actionInstruction = "Chuẩn hóa định dạng LaTeX, sửa lỗi cú pháp cơ bản và trình bày lại nội dung sạch sẽ.";
  }

  const prompt = `
    Nhiệm vụ: ${actionInstruction}

    Yêu cầu quan trọng:
    1. GIỮ NGUYÊN 100% nội dung chữ và mã LaTeX quan trọng, không được tóm tắt hay lược bỏ nội dung chính.
    2. Chỉ thực hiện thao tác: ${actionInstruction}.
    3. Trả về mã LaTeX đã qua xử lý. Không thêm lời dẫn giải của AI.
    4. Nếu nội dung quá lớn, hãy đảm bảo tính toàn vẹn của cấu trúc file.

    Nội dung LaTeX gốc:
    ---
    ${texContent}
    ---
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.1, // Low temperature for high fidelity
      }
    });

    return response.text || "Không thể xử lý nội dung này.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Lỗi khi kết nối với AI. Vui lòng thử lại sau.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { processTexContent, ProcessingAction } from './services/geminiService';

const App: React.FC = () => {
  const [rawText, setRawText] = useState<string>("");
  const [processedText, setProcessedText] = useState<string>("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [statusMsg, setStatusMsg] = useState<string>("Sẵn sàng xử lý dữ liệu");
  const [questionCount, setQuestionCount] = useState<number>(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to count questions (heuristic based on common LaTeX tags)
  useEffect(() => {
    const count = (rawText.match(/\\begin\{ex\}|\\begin\{question\}|\\item/g) || []).length;
    setQuestionCount(count);
  }, [rawText]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    let combinedText = "";
    for (let i = 0; i < files.length; i++) {
      const text = await files[i].text();
      combinedText += (combinedText ? "\n\n" : "") + `% FILE: ${files[i].name}\n` + text;
    }

    setRawText(prev => prev + (prev ? "\n\n" : "") + combinedText);
    setStatusMsg(`Đã tải lên ${files.length} tệp.`);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAction = async (action: ProcessingAction) => {
    if (!rawText.trim()) {
      setStatusMsg("Vui lòng nhập hoặc tải lên dữ liệu LaTeX trước.");
      return;
    }

    setIsProcessing(true);
    setStatusMsg("Đang xử lý với AI Gemini...");
    try {
      const result = await processTexContent(rawText, action);
      setProcessedText(result);
      setStatusMsg("Xử lý hoàn tất!");
    } catch (err: any) {
      setStatusMsg(`Lỗi: ${err.message}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(processedText);
    setStatusMsg("Đã sao chép vào bộ nhớ tạm!");
    setTimeout(() => setStatusMsg("Sẵn sàng"), 2000);
  };

  return (
    <div className="min-h-screen flex flex-col p-4 md:p-6 pb-24">
      {/* Header Info */}
      <div className="flex justify-between items-center mb-6">
        <div className="flex items-center space-x-2">
          <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse"></div>
          <h1 className="text-xl font-bold tracking-tight text-blue-100">TexRead Pro <span className="text-xs font-normal text-slate-500">v2.0</span></h1>
        </div>
        <div className="flex gap-4">
           <button 
            onClick={() => fileInputRef.current?.click()}
            className="px-4 py-1.5 bg-blue-600/20 hover:bg-blue-600/40 border border-blue-500/50 rounded-lg text-sm font-medium transition-all flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
            Tải file .tex
          </button>
          <input type="file" ref={fileInputRef} className="hidden" multiple accept=".tex" onChange={handleFileUpload} />
        </div>
      </div>

      {/* Main Panels */}
      <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 mb-4">

        {/* RAW DATA PANEL */}
        <div className="flex flex-col glass-panel rounded-xl overflow-hidden shadow-2xl">
          <div className="px-4 py-3 bg-slate-900/80 border-b border-blue-500/20 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <span className="w-2.5 h-2.5 rounded-full bg-pink-500"></span>
              <span className="text-xs font-bold uppercase tracking-wider text-slate-300">DỮ LIỆU LATEX THÔ</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="bg-pink-500/10 text-pink-500 text-[10px] px-2 py-0.5 rounded-full border border-pink-500/20">{questionCount} câu</span>
              <button onClick={() => setRawText("")} className="text-slate-400 hover:text-white transition-colors">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              </button>
            </div>
          </div>
          <textarea
            value={rawText}
            onChange={(e) => setRawText(e.target.value)}
            placeholder="Kéo thả file .tex hoặc dán nội dung vào đây..."
            className="flex-1 bg-transparent p-4 text-sm monospace resize-none focus:outline-none text-slate-300 leading-relaxed placeholder:text-slate-600"
          />
        </div>

        {/* PROCESSED RESULT PANEL */}
        <div className="flex flex-col glass-panel rounded-xl overflow-hidden shadow-2xl">
          <div className="px-4 py-3 bg-slate-900/80 border-b border-blue-500/20 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <span className="w-2.5 h-2.5 rounded-full bg-green-500"></span>
              <span className="text-xs font-bold uppercase tracking-wider text-slate-300">KẾT QUẢ CHUẨN HÓA</span>
            </div>
            <div className="flex items-center gap-3">
              <button 
                onClick={copyToClipboard}
                className="flex items-center gap-1.5 px-3 py-1 bg-blue-600/20 hover:bg-blue-600/40 border border-blue-500/50 rounded-md text-[10px] font-bold text-blue-400 transition-all active:scale-95"
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
                SAO CHÉP
              </button>
            </div>
          </div>
          <div className="flex-1 relative">
