import { GoogleGenAI } from "@google/genai";

export type ProcessingAction = 'REMOVE_ID' | 'REMOVE_SOLUTION' | 'SORT_NO_SUB' | 'SORT_FORMAT';

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const processTexContent = async (texContent: string, action: ProcessingAction): Promise<string> => {
  const ai = getAIClient();

  let actionInstruction = "";
  switch(action) {
    case 'REMOVE_ID':
      actionInstruction = "Xóa toàn bộ các mã ID định dạng %[...] hoặc ID nằm trong ngoặc vuông thường dùng để phân loại câu hỏi. Giữ nguyên 100% nội dung câu hỏi và mã LaTeX khác.";
      break;
    case 'REMOVE_SOLUTION':
      actionInstruction = "Xóa toàn bộ các môi trường lời giải (như \\begin{solution}...\\end{solution}, \\loigiai{...}, v.v.). Giữ nguyên 100% đề bài và đáp án.";
      break;
    case 'SORT_NO_SUB':
      actionInstruction = "Sắp xếp lại các câu hỏi theo thứ tự (ví dụ Chương -> Bài -> Mức độ) nhưng KHÔNG được thay đổi hay can thiệp vào các câu hỏi phụ (sub-questions). Giữ nguyên 100% nội dung.";
      break;
    case 'SORT_FORMAT':
      actionInstruction = "Sắp xếp lại các câu hỏi và chuẩn hóa định dạng (ví dụ dùng '\\\\' cho xuống dòng, thụt đầu dòng chuẩn). Giữ nguyên 100% nội dung text.";
      break;
  }

  const prompt = `
    Nhiệm vụ: ${actionInstruction}

    YÊU CẦU NGHIÊM NGẶT:
    1. KHÔNG TÓM TẮT. KHÔNG LÀM MẤT NỘI DUNG. Giữ nguyên 100% văn bản và mã LaTeX không liên quan đến yêu cầu xóa.
    2. Chỉ thực hiện thao tác: ${actionInstruction}.
    3. Trả về mã LaTeX sạch. Không thêm bất kỳ lời dẫn hay bình luận nào của AI.

    Nội dung LaTeX cần xử lý:
    ---
    ${texContent}
    ---
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.1,
        topP: 0.1,
      }
    });

    return response.text || "Lỗi: Không nhận được phản hồi từ AI.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Không thể kết nối với AI. Vui lòng kiểm tra lại kết nối.");
  }
};

